#include <stdio.h>
#include <stdlib.h>
#define MAXN 200005

typedef struct Node {
    int color;
    int lucky;
    int ans;
    struct Node* next;
} Node;

Node* nodes[MAXN];
int N;

void dfs(Node* node, Node* parent) {
    // Calculate the frequency of each color in the subtree of the current node
    int freq[1000005] = {0};
    freq[node->color]++;

    Node* child = node->next;
    while (child != NULL) {
        if (child != parent) {
            dfs(child, node);
            // Update the frequency of each color
            for (int i = 0; i < 1000005; i++) {
                freq[i] += child->freq[i];
            }
        }
        child = child->next;
    }

    // Calculate the answer for the current node
    node->ans = 0;
    for (int i = 0; i < 1000005; i++) {
        if (freq[i] == node->lucky) {
            node->ans++;
        }
    }
}

int main() {
    scanf("%d", &N);

    for (int i = 1; i <= N; i++) {
        nodes[i] = (Node*)malloc(sizeof(Node));
        scanf("%d", &nodes[i]->color);
    }

    for (int i = 1; i <= N; i++) {
        scanf("%d", &nodes[i]->lucky);
    }

    for (int i = 1; i < N; i++) {
        int x, y;
        scanf("%d %d", &x, &y);
        Node* newNode = (Node*)malloc(sizeof(Node));
        newNode->next = nodes[x]->next;
        nodes[x]->next = newNode;
        newNode->color = nodes[y]->color;
        newNode->lucky = nodes[y]->lucky;
    }

    dfs(nodes[1], NULL);

    for (int i = 1; i <= N; i++) {
        printf("%d ", nodes[i]->ans);
    }

    return 0;
}

