#include <iostream>
#include <vector>
#include <unordered_map>
using namespace std;

const int MAXN = 200005;

struct Node {
    int color;
    int lucky;
    int ans;
    vector<int> children;
};

Node nodes[MAXN];
int N;

void dfs(int node, int parent) {
    // Calculate the frequency of each color in the subtree of the current node
    unordered_map<int, int> freq;
    freq[nodes[node].color]++;

    for (int child : nodes[node].children) {
        if (child != parent) {
            dfs(child, node);
            // Update the frequency of each color
            for (auto& pair : nodes[child].freq) {
                freq[pair.first] += pair.second;
            }
        }
    }

    // Calculate the answer for the current node
    nodes[node].ans = 0;
    for (auto& pair : freq) {
        if (pair.second == nodes[node].lucky) {
            nodes[node].ans++;
        }
    }
}

int main() {
    cin >> N;

    for (int i = 1; i <= N; i++) {
        cin >> nodes[i].color;
    }

    for (int i = 1; i <= N; i++) {
        cin >> nodes[i].lucky;
    }

    for (int i = 1; i < N; i++) {
        int x, y;
        cin >> x >> y;
        nodes[x].children.push_back(y);
        nodes[y].children.push_back(x);
    }

    dfs(1, -1);

    for (int i = 1; i <= N; i++) {
        cout << nodes[i].ans << " ";
    }

    return 0;
}

