import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Scanner;

public class Main {
    static class Node {
        int color;
        int lucky;
        int ans;
        List<Node> children;
        Map<Integer, Integer> freq;

        public Node() {
            children = new ArrayList<>();
            freq = new HashMap<>();
        }
    }

    static Node[] nodes;
    static int N;

    public static void dfs(Node node, Node parent) {
        // Calculate the frequency of each color in the subtree of the current node
        node.freq.put(node.color, node.freq.getOrDefault(node.color, 0) + 1);

        for (Node child : node.children) {
            if (child != parent) {
                dfs(child, node);
                // Update the frequency of each color
                for (Map.Entry<Integer, Integer> entry : child.freq.entrySet()) {
                    node.freq.put(entry.getKey(), node.freq.getOrDefault(entry.getKey(), 0) + entry.getValue());
                }
            }
        }

        // Calculate the answer for the current node
        node.ans = 0;
        for (Map.Entry<Integer, Integer> entry : node.freq.entrySet()) {
            if (entry.getValue() == node.lucky) {
                node.ans++;
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        N = scanner.nextInt();
        nodes = new Node[N + 1];

        for (int i = 1; i <= N; i++) {
            nodes[i] = new Node();
            nodes[i].color = scanner.nextInt();
        }

        for (int i = 1; i <= N; i++) {
            nodes[i].lucky = scanner.nextInt();
        }

        for (int i = 1; i < N; i++) {
            int x = scanner.nextInt();
            int y = scanner.nextInt();
            nodes[x].children.add(nodes[y]);
            nodes[y].children.add(nodes[x]);
        }

        dfs(nodes[1], null);

        for (int i = 1; i <= N; i++) {
            System.out.print(nodes[i].ans + " ");
        }
    }
}

